    /** Build 30 questions from a fillers 15 term/definition pairs: 15 identification + 15 MC. */
    private static function generateFiller(string $code): array
    {
        $pairs = self::FILLER[$code] ?? [];
        $n = count($pairs);
        $questions = [];

        // Definition → term (identification).
        foreach ($pairs as [$term, $definition]) {
            $questions[] = ['Identify the term described: '.$definition.'.', 'identification', null, $term];
        }

        // Term → correct definition (multiple choice), distractors pulled from sibling pairs.
        $letters = ['A', 'B', 'C', 'D'];
        foreach ($pairs as $i => [$term, $definition]) {
            $distractors = [
                $pairs[($i + 1) % $n][1],
                $pairs[($i + 2) % $n][1],
                $pairs[($i + 3) % $n][1],
            ];
            $correctPos = $i % 4;
            $choices = [];
            $d = 0;
            for ($p = 0; $p < 4; $p++) {
                $choices[$letters[$p]] = $p === $correctPos ? $definition : $distractors[$d++];
            }
            $questions[] = ['Which of the following best describes "'.$term.'"?', 'multiple_choice', $choices, $letters[$correctPos]];
        }

        return $questions;
    }
